        max: Optional['types.GameMaxAggregateInput'] = None,
        having: Optional['types.GameScalarWhereWithAggregatesInput'] = None,
        count: Optional[Union[bool, 'types.GameCountAggregateInput']] = None,
        order: Optional[Union[Mapping['types.GameScalarFieldKeys', 'types.SortOrder'], List[Mapping['types.GameScalarFieldKeys', 'types.SortOrder']]]] = None,
